import java.awt.geom.AffineTransform;
import java.nio.file.Path;
import java.nio.file.Paths;

import static org.junit.jupiter.api.Assertions.assertTrue;

class OFDPageGraphics2DTest {

    @Test
    void setTransform() throws Exception {
        final Path dst = Paths.get("target/complexCTMSetAndReset.ofd");
        try (OFDGraphicsDocument doc = new OFDGraphicsDocument(dst)) {
            OFDPageGraphics2D g = doc.newPage(500, 500);

            // Apply initial rotation and translation
            g.rotate(Math.PI / 6);
            g.translate(100, 50);
            g.setColor(Color.RED);
            g.fillRect(20, 20, 100, 60);

            // Reset transformation matrix, then apply new translation and rotation
            g.setTransform(new AffineTransform());
            g.translate(200, 150);
            g.rotate(Math.PI / 4);
            g.setColor(Color.BLUE);
            g.fillRect(20, 20, 100, 60);
        }
        // Verify file generation after closing the document
        assertTrue(dst.toFile().exists());
    }

}

