import static org.junit.jupiter.api.Assertions.*;

public class PageLayoutTest {

    @Test
    public void testEquals() {
        // Precondition 1: Use static method A4 to get a predefined layout
        PageLayout layout1 = PageLayout.A4();

        // Precondition 2: Create another layout with same dimensions via constructor
        // A4 dimensions are 210.0 x 297.0 mm (common standard)
        PageLayout layout2 = new PageLayout(210.0, 297.0);
        // Set margins to match the default margins from layout1 (25.4, 31.7, 25.4, 31.7)
        layout2.setMargin(25.4);
        layout2.setMarginRight(31.7);
        layout2.setMarginLeft(31.7);

        // Expected Result 1: Same instance equals itself
        assertTrue(layout1.equals(layout1), "Same instance should be equal to itself");

        // Expected Result 2: Two different layouts with same dimensions and margins are equal
        assertTrue(layout1.equals(layout2), "Two layouts with same dimensions and margins should be equal");

        // Additional verification: symmetry
        assertTrue(layout2.equals(layout1), "Equals should be symmetric");
    }
}

