        double width = canvas.getWidth();
        double height = canvas.getHeight();
        TextMetrics textMetrics = ctx.measureText(this.value);


        LinkedList<TextLine> lines = new LinkedList<>();
        double textLineWidth = 0;
        int offset = 0;
        // 分段
