                            return false;
                        }
                    }
                }
                if (AFloat.center == div.getFloat()) {
                    return false;
                }
            }
        }
        // 段内不含元素时直接加入

        this.remainWidth -= blockSize.getWidth();
        add(div, blockSize);
        return true;
