private Segment[] segmentBlocking(Segment segment, Rectangle area) {
    // 分为两块
    Segment sgm1 = new Segment(segment.getWidth());
    Segment sgmNext = new Segment(segment.getWidth());
    for (Map.Entry<Div, Rectangle> item : segment) {
        Div div = item.getKey();
        Rectangle rec = item.getValue();
        // 1. 能够放置到剩余空间中
        double availableHeight = area.getHeight();
        if (rec.getHeight() <= availableHeight) {
            // 向第一个段，加入实际的Div
            sgm1.tryAdd(div);
            // 向第下一个段加入占位符
            sgmNext.tryAdd(Div.placeholder(rec, div.getFloat()));
            continue;
        }
        // 2. 在剩余空间中无法放置，且元素本身不可分割
        if (div.isIntegrity()) {
            // 向第一个段中加入占位符
            sgm1.tryAdd(Div.placeholder(rec.getWidth(), availableHeight, div.getFloat()));
            // 把实际元素加入下一个段中
            sgmNext.tryAdd(div);
            continue;
        }
        // 3. 无法在剩余空间中放置，且可以分割的情况，需要对元素进行分割
        Div[] split = div.split(availableHeight);
        sgm1.tryAdd(split[0]);
        sgmNext.tryAdd(split[1]);
    }
    return new Segment[]{sgm1, sgmNext};
}

public List<Segment> process(List<Div> streamLayoutQueue) {
    // 可用于布局的宽度
    double width = pageLayout.contentWidth();
    if (streamLayoutQueue == null || streamLayoutQueue.isEmpty()) {
        return Collections.emptyList();
    }
    LinkedList<Segment> res = new LinkedList<>();
    LinkedList<Div> seq = new LinkedList<>(streamLayoutQueue);
    Segment segment = new Segment(width);
    while (!seq.isEmpty()) {
        Div div = seq.pop();
        if (div.getPosition() == Position.Absolute) {
            continue;
        }
        if (div instanceof BR) {
            if (segment.isEmpty()) {
                // 如果段为空，那么不需要换行
                continue;
            }
            // 换行符
            res.add(segment);
            segment = new Segment(width);
            continue;
        }
        // 尝试将元素加入段中
        boolean addSuccess = segment.tryAdd(div);
        // 如果段已经满了，那么加入了段队列中
        if (!addSuccess && !segment.isEmpty()) {
            // 段已经无法再容纳元素： 无法加入元素且不为空
            res.add(segment);
            segment =  new Segment(width);
            seq.push(div);
        }
    }
    // 处理最后一个段的情况
    if (!segment.isEmpty()) {
        res.add(segment);
    }
    return res;
}

