     *
     * @return 签名ID，形如：'001'
     */
    @Override
    public String incrementAndGet() {
        int newSignID = provider.incrementAndGet();
        if (enableZeroPrefix) {
            return String.format("%03d", newSignID);
        } else {
            return String.valueOf(newSignID);
        }
    }

